import React from 'react';
import { Document, Page } from 'react-pdf';

import resumePDF from './Austin Meyer Resume - 2022.pdf';


function Resume() {
    try {  
        return (
            <Document file={resumePDF}>
                <Page pageNumber={1} />
            </Document>
        )
    } catch (error) {
    console.log(error)
}
}

export default Resume;
